import acm.program.*;
import acm.graphics.*;
import javax.swing.*;
import java.awt.event.*;

public class ClickCounter extends GraphicsProgram {
    private int count = 0;
    private JLabel label;

    public void init() {
        label = new JLabel("Count: 0");
        add(label, SOUTH);
        add(new JButton("Count"), SOUTH);
        addActionListeners();
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getActionCommand().equals("Count")) {
            count++;
            label.setText("Count: " + count);
        }
    }
}

import acm.program.*;
import acm.graphics.*;
import javax.swing.*;
import java.awt.event.*;

public class TextAdder extends GraphicsProgram {
    private JTextField input;

    public void init() {
        add(new JLabel("Text:"), SOUTH);
        input = new JTextField(12);
        add(input, SOUTH);
        add(new JButton("Add"), SOUTH);
        addActionListeners();
        input.addActionListener(this);
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getActionCommand().equals("Add") || e.getSource() == input) {
            String s = input.getText().trim();
            if (!s.isEmpty()) {
                GLabel label = new GLabel(s, 20, 50);
                add(label);
                input.setText("");
            }
        }
    }
}

import acm.program.*;
import acm.graphics.*;
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class ColorChooser extends GraphicsProgram {
    private GRect swatch;
    private JRadioButton red, green, blue;

    public void init() {
        red = new JRadioButton("Red");
        green = new JRadioButton("Green");
        blue = new JRadioButton("Blue");
        ButtonGroup group = new ButtonGroup();
        group.add(red);
        group.add(green);
        group.add(blue);
        add(red, SOUTH);
        add(green, SOUTH);
        add(blue, SOUTH);
        addActionListeners();

        swatch = new GRect(50, 50, 100, 60);
        swatch.setFilled(true);
        swatch.setFillColor(Color.RED);
        add(swatch);
        red.setSelected(true);
    }

    public void actionPerformed(ActionEvent e) {
        if (red.isSelected()) swatch.setFillColor(Color.RED);
        else if (green.isSelected()) swatch.setFillColor(Color.GREEN);
        else if (blue.isSelected()) swatch.setFillColor(Color.BLUE);
    }
}

